    @overload
    async def count(
        self,
        select: None = None,
        take: Optional[int] = None,
        skip: Optional[int] = None,
        where: Optional[types.FrameworkWhereInput] = None,
        cursor: Optional[types.FrameworkWhereUniqueInput] = None,
    ) -> int:
        """Count the number of Framework records present in the database

        Parameters
        ----------
        select
            Select the Framework fields to be counted
        take
            Limit the maximum result
        skip
            Ignore the first N records
        where
            Framework filter to find records
        cursor
            Specifies the position in the list to start counting results from, (typically an ID field)
        order
            This parameter is deprecated and will be removed in a future release

        Returns
        -------
        int
            The total number of records found, returned if `select` is not given

        prisma.types.FrameworkCountAggregateOutput
            Data returned when `select` is used, the fields present in this dictionary will
            match the fields passed in the `select` argument

        Raises
        ------
        prisma.errors.PrismaError
            Catch all for every exception raised by Prisma Client Python

        Example
        -------
        ```py
        # total: int
        total = await Framework.prisma().count()

        # results: prisma.types.FrameworkCountAggregateOutput
        results = await Framework.prisma().count(
            select={
                '_all': True,
                'id': True,
            },
        )
        ```
        """


    @overload
    async def count(
        self,
        select: types.FrameworkCountAggregateInput,
        take: Optional[int] = None,
        skip: Optional[int] = None,
        where: Optional[types.FrameworkWhereInput] = None,
        cursor: Optional[types.FrameworkWhereUniqueInput] = None,
    ) -> types.FrameworkCountAggregateOutput:
        ...

    async def count(
        self,
        select: Optional[types.FrameworkCountAggregateInput] = None,
        take: Optional[int] = None,
        skip: Optional[int] = None,
        where: Optional[types.FrameworkWhereInput] = None,
        cursor: Optional[types.FrameworkWhereUniqueInput] = None,
    ) -> Union[int, types.FrameworkCountAggregateOutput]:
        """Count the number of Framework records present in the database

        Parameters
        ----------
        select
            Select the Framework fields to be counted
        take
            Limit the maximum result
        skip
            Ignore the first N records
        where
            Framework filter to find records
        cursor
            Specifies the position in the list to start counting results from, (typically an ID field)
        order
            This parameter is deprecated and will be removed in a future release

        Returns
        -------
        int
            The total number of records found, returned if `select` is not given

        prisma.types.FrameworkCountAggregateOutput
            Data returned when `select` is used, the fields present in this dictionary will
            match the fields passed in the `select` argument

        Raises
        ------
        prisma.errors.PrismaError
            Catch all for every exception raised by Prisma Client Python

        Example
        -------
        ```py
        # total: int
        total = await Framework.prisma().count()

        # results: prisma.types.FrameworkCountAggregateOutput
        results = await Framework.prisma().count(
            select={
                '_all': True,
                'name': True,
            },
        )
        ```
        """

        # TODO: this selection building should be moved to the QueryBuilder
        #
        # note the distinction between checking for `not select` here and `select is None`
        # later is to handle the case that the given select dictionary is empty, this
        # is a limitation of our types.
        if not select:
            root_selection = ['_count { _all }']
        else:

            root_selection = [
                '_count {{ {0} }}'.format(' '.join(k for k, v in select.items() if v is True))
            ]

        resp = await self._client._execute(
            method='count',
            model=self._model,
            arguments={
                'take': take,
                'skip': skip,
                'where': where,
                'cursor': cursor,
            },
            root_selection=root_selection,
        )

        if select is None:
            return cast(int, resp['data']['result']['_count']['_all'])
        else:
            return cast(types.FrameworkCountAggregateOutput, resp['data']['result']['_count'])

